"use client"

import { useState, useRef, useCallback } from "react"
import { Wand2, Sparkles, Crop, Zap, Download, Upload, RefreshCw, Sun, Contrast, Droplets, SlidersHorizontal } from "lucide-react"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs"
import { Slider } from "@/components/ui/slider"
import { Label } from "@/components/ui/label"
import { Input } from "@/components/ui/input"
import { useToast } from "@/hooks/use-toast"
import { Badge } from "@/components/ui/badge"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"

const API_BASE = process.env.NEXT_PUBLIC_API_URL || "http://localhost:8000"

type ResultImage = { fileId: string; url: string }

const CROP_PRESETS = [
  { label: "Square (1:1)", value: "square", icon: "⬛" },
  { label: "Portrait (4:5)", value: "portrait", icon: "▬" },
  { label: "Landscape (16:9)", value: "landscape", icon: "▬" },
  { label: "Tight Crop", value: "tight", icon: "✂️" },
  { label: "Amazon (85%)", value: "amazon", icon: "📦" },
]

export default function EnhancePage() {
  const [uploadedFile, setUploadedFile] = useState<File | null>(null)
  const [uploadedPreviewUrl, setUploadedPreviewUrl] = useState<string | null>(null)
  const [fileId, setFileId] = useState("")
  const [processing, setProcessing] = useState(false)
  const [resultImage, setResultImage] = useState<ResultImage | null>(null)
  const [resizeResults, setResizeResults] = useState<any[]>([])
  const [isDraggingOver, setIsDraggingOver] = useState(false)

  // Manual controls
  const [brightness, setBrightness] = useState(1.0)
  const [contrast, setContrast] = useState(1.0)
  const [saturation, setSaturation] = useState(1.0)
  const [sharpness, setSharpness] = useState(1.0)
  const [cropMode, setCropMode] = useState("square")
  const [customW, setCustomW] = useState("800")
  const [customH, setCustomH] = useState("800")

  const fileInputRef = useRef<HTMLInputElement>(null)
  const { toast } = useToast()

  /** CSS filter string for live preview */
  const cssFilter = `brightness(${brightness}) contrast(${contrast}) saturate(${saturation})`

  const uploadFile = async (file: File): Promise<string> => {
    const fd = new FormData()
    fd.append("file", file)
    const res = await fetch(`${API_BASE}/upload-asset`, { method: "POST", body: fd })
    if (!res.ok) throw new Error("Upload failed")
    const data = await res.json()
    return data.file_id
  }

  const handleFileDrop = useCallback(async (file: File) => {
    setUploadedFile(file)
    setUploadedPreviewUrl(URL.createObjectURL(file))
    setResultImage(null)
    setProcessing(true)
    try {
      const id = await uploadFile(file)
      setFileId(id)
      toast({ title: "Uploaded!", description: "File ready for processing" })
    } catch (e: any) {
      toast({ title: "Upload failed", description: e.message, variant: "destructive" })
    } finally {
      setProcessing(false)
    }
  }, [])

  const onDrop = (e: React.DragEvent) => {
    e.preventDefault(); setIsDraggingOver(false)
    const file = e.dataTransfer.files[0]
    if (file && file.type.startsWith("image/")) handleFileDrop(file)
  }

  const applyManualEnhance = async () => {
    if (!fileId) return toast({ title: "No file", description: "Upload an image first", variant: "destructive" })
    setProcessing(true)
    try {
      const res = await fetch(`${API_BASE}/enhance/manual`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ file_id: fileId, brightness, contrast, saturation, sharpness }),
      })
      if (!res.ok) throw new Error((await res.json()).detail)
      const data = await res.json()
      setResultImage({ fileId: data.new_file_id, url: `${API_BASE}/asset/${data.new_file_id}` })
      toast({ title: "Enhancement Applied!" })
    } catch (e: any) {
      toast({ title: "Enhancement failed", description: e.message, variant: "destructive" })
    } finally {
      setProcessing(false)
    }
  }

  const applySmartEnhance = async (upscale = false) => {
    if (!fileId) return toast({ title: "No file", description: "Upload an image first", variant: "destructive" })
    setProcessing(true)
    try {
      const res = await fetch(`${API_BASE}/smart-enhance/${fileId}?upscale=${upscale}`)
      if (!res.ok) throw new Error((await res.json()).detail)
      const data = await res.json()
      setResultImage({ fileId: data.new_file_id, url: `${API_BASE}/asset/${data.new_file_id}` })
      toast({ title: "Smart Enhancement Complete" })
    } catch (e: any) {
      toast({ title: "Failed", description: e.message, variant: "destructive" })
    } finally {
      setProcessing(false)
    }
  }

  const applyCrop = async () => {
    if (!fileId) return toast({ title: "No file", description: "Upload an image first", variant: "destructive" })
    setProcessing(true)
    try {
      const params = new URLSearchParams({ mode: cropMode })
      if (cropMode === "custom") { params.append("width", customW); params.append("height", customH) }
      const res = await fetch(`${API_BASE}/smart-crop/${fileId}?${params}`)
      if (!res.ok) throw new Error((await res.json()).detail)
      const data = await res.json()
      setResultImage({ fileId: data.new_file_id, url: `${API_BASE}/asset/${data.new_file_id}` })
      toast({ title: "Crop Complete", description: `Cropped to ${cropMode} format` })
    } catch (e: any) {
      toast({ title: "Crop failed", description: e.message, variant: "destructive" })
    } finally {
      setProcessing(false)
    }
  }

  const handleAutoResize = async () => {
    if (!fileId) return toast({ title: "No file", description: "Upload an image first", variant: "destructive" })
    setProcessing(true)
    try {
      const res = await fetch(`${API_BASE}/auto-resize/${fileId}`)
      if (!res.ok) throw new Error((await res.json()).detail)
      const data = await res.json()
      setResizeResults(data.files.map((f: any) => ({ ...f, url: `${API_BASE}/asset/${f.file_id}` })))
      toast({ title: "Resize Complete", description: `${data.files.length} formats generated` })
    } catch (e: any) {
      toast({ title: "Resize failed", description: e.message, variant: "destructive" })
    } finally {
      setProcessing(false)
    }
  }

  const downloadResult = (url: string, name: string) => {
    const a = document.createElement("a")
    a.href = url; a.download = name; a.click()
  }

  const UploadZone = () => (
    <div
      className={`relative border-2 border-dashed rounded-xl p-8 text-center transition-colors cursor-pointer ${isDraggingOver ? "border-primary bg-primary/5" : "border-border hover:border-primary/50 hover:bg-muted/30"}`}
      onDrop={onDrop}
      onDragOver={e => { e.preventDefault(); setIsDraggingOver(true) }}
      onDragLeave={() => setIsDraggingOver(false)}
      onClick={() => fileInputRef.current?.click()}
    >
      <input ref={fileInputRef} type="file" accept="image/*" className="hidden"
        onChange={e => { if (e.target.files?.[0]) handleFileDrop(e.target.files[0]); e.target.value = "" }} />
      {uploadedPreviewUrl ? (
        <div className="space-y-2">
          <img src={uploadedPreviewUrl} alt="preview" className="max-h-48 mx-auto rounded-lg object-contain" style={{ filter: cssFilter }} />
          <p className="text-sm font-medium">{uploadedFile?.name}</p>
          <Badge variant="secondary" className="text-xs">ID: {fileId.substring(0, 16)}...</Badge>
          <p className="text-xs text-muted-foreground">Click to change image</p>
        </div>
      ) : (
        <>
          <Upload className="h-12 w-12 mx-auto mb-3 text-muted-foreground opacity-50" />
          <p className="font-medium">Drop an image here or click to upload</p>
          <p className="text-sm text-muted-foreground mt-1">PNG, JPG, WebP supported</p>
        </>
      )}
      {processing && (
        <div className="absolute inset-0 bg-background/80 rounded-xl flex items-center justify-center">
          <RefreshCw className="h-6 w-6 animate-spin text-primary" />
        </div>
      )}
    </div>
  )

  const ResultPanel = () => resultImage ? (
    <div className="space-y-3">
      <div className="flex items-center justify-between">
        <p className="text-sm font-semibold">Result</p>
        <Badge className="bg-green-500">Ready</Badge>
      </div>
      <div className="rounded-xl border overflow-hidden bg-muted/30">
        <img src={resultImage.url} alt="result" className="w-full max-h-64 object-contain" />
      </div>
      <Button className="w-full gap-2 gradient-primary h-10" onClick={() => downloadResult(resultImage.url, `enhanced.png`)}>
        <Download className="h-4 w-4" /> Download Result
      </Button>
    </div>
  ) : null

  return (
    <div className="flex h-full flex-col">
      <div className="border-b border-border bg-card px-8 py-6">
        <h1 className="text-3xl font-bold tracking-tight">Smart Enhancement</h1>
        <p className="mt-1 text-muted-foreground">AI-powered image optimization with manual controls</p>
      </div>

      <div className="flex-1 overflow-auto p-8">
        <div className="mx-auto max-w-6xl">
          <Tabs defaultValue="manual" className="w-full">
            <TabsList className="grid w-full max-w-xl grid-cols-4">
              <TabsTrigger value="manual" className="gap-1.5"><SlidersHorizontal className="h-3.5 w-3.5" />Manual</TabsTrigger>
              <TabsTrigger value="ai" className="gap-1.5"><Wand2 className="h-3.5 w-3.5" />AI Enhance</TabsTrigger>
              <TabsTrigger value="crop" className="gap-1.5"><Crop className="h-3.5 w-3.5" />Crop</TabsTrigger>
              <TabsTrigger value="resize" className="gap-1.5"><Zap className="h-3.5 w-3.5" />Multi-Size</TabsTrigger>
            </TabsList>

            {/* ── Manual Controls ── */}
            <TabsContent value="manual" className="mt-6">
              <div className="grid gap-6 lg:grid-cols-2">
                <div className="space-y-5">
                  <UploadZone />
                  <Card>
                    <CardHeader className="pb-3"><CardTitle className="text-base">Manual Adjustments</CardTitle></CardHeader>
                    <CardContent className="space-y-5">
                      {[
                        { label: "Brightness", icon: <Sun className="h-4 w-4 text-yellow-500" />, value: brightness, setter: setBrightness, min: 0.3, max: 2.0, step: 0.05 },
                        { label: "Contrast", icon: <Contrast className="h-4 w-4 text-blue-500" />, value: contrast, setter: setContrast, min: 0.3, max: 2.0, step: 0.05 },
                        { label: "Saturation", icon: <Droplets className="h-4 w-4 text-purple-500" />, value: saturation, setter: setSaturation, min: 0.0, max: 3.0, step: 0.05 },
                        { label: "Sharpness", icon: <Sparkles className="h-4 w-4 text-green-500" />, value: sharpness, setter: setSharpness, min: 0.0, max: 3.0, step: 0.05 },
                      ].map(({ label, icon, value, setter, min, max, step }) => (
                        <div key={label} className="space-y-2">
                          <div className="flex items-center justify-between">
                            <div className="flex items-center gap-2">{icon}<Label className="text-sm">{label}</Label></div>
                            <div className="flex items-center gap-2">
                              <span className="text-sm font-mono w-10 text-right">{value.toFixed(2)}</span>
                              <Button size="sm" variant="ghost" className="h-6 text-xs px-2" onClick={() => setter(1.0)}>Reset</Button>
                            </div>
                          </div>
                          <Slider value={[value]} onValueChange={([v]) => setter(v)} min={min} max={max} step={step} />
                        </div>
                      ))}
                      <div className="flex gap-2 pt-2">
                        <Button className="flex-1 gradient-primary gap-2" onClick={applyManualEnhance} disabled={!fileId || processing}>
                          {processing ? <RefreshCw className="h-4 w-4 animate-spin" /> : <Wand2 className="h-4 w-4" />}
                          Apply
                        </Button>
                        <Button variant="outline" className="px-3 bg-transparent" onClick={() => { setBrightness(1); setContrast(1); setSaturation(1); setSharpness(1) }}>
                          Reset All
                        </Button>
                      </div>
                    </CardContent>
                  </Card>
                </div>
                <div className="space-y-4">
                  {uploadedPreviewUrl && (
                    <div className="grid grid-cols-2 gap-3">
                      <div>
                        <p className="text-xs font-medium mb-2 text-muted-foreground">ORIGINAL</p>
                        <img src={uploadedPreviewUrl} alt="original" className="w-full rounded-xl border object-contain max-h-56 bg-muted/30" />
                      </div>
                      <div>
                        <p className="text-xs font-medium mb-2 text-muted-foreground">PREVIEW (CSS)</p>
                        <img src={uploadedPreviewUrl} alt="preview" className="w-full rounded-xl border object-contain max-h-56 bg-muted/30" style={{ filter: cssFilter }} />
                      </div>
                    </div>
                  )}
                  <ResultPanel />
                </div>
              </div>
            </TabsContent>

            {/* ── AI Enhance ── */}
            <TabsContent value="ai" className="mt-6">
              <div className="grid gap-6 lg:grid-cols-2">
                <div className="space-y-4">
                  <UploadZone />
                  <div className="grid grid-cols-2 gap-3">
                    <Button className="gradient-primary h-14 flex-col gap-1" onClick={() => applySmartEnhance(false)} disabled={!fileId || processing}>
                      <Wand2 className="h-5 w-5" /><span className="text-xs">Smart Enhance</span>
                    </Button>
                    <Button variant="outline" className="h-14 flex-col gap-1 bg-transparent" onClick={() => applySmartEnhance(true)} disabled={!fileId || processing}>
                      <Sparkles className="h-5 w-5" /><span className="text-xs">Enhance + Upscale 2×</span>
                    </Button>
                  </div>
                </div>
                <div className="space-y-4">
                  <Card>
                    <CardHeader className="pb-2"><CardTitle className="text-base">AI Processing Pipeline</CardTitle></CardHeader>
                    <CardContent className="space-y-2">
                      {[
                        ["Auto White Balance", "Gray-world algorithm corrects color temperature"],
                        ["Shadow/Highlight Recovery", "Balanced exposure in dark and bright areas"],
                        ["Smart Contrast", "Histogram equalization in YCrCb space"],
                        ["Noise Reduction", "Bilateral filter preserving edges"],
                        ["Adaptive Sharpening", "Based on Laplacian blur detection"],
                        ["2× HD Upscale", "(Optional) Bicubic super-resolution"],
                      ].map(([title, desc]) => (
                        <div key={title} className="flex gap-2 text-sm py-1.5 border-b last:border-0 border-border/50">
                          <div className="h-5 w-5 rounded-full bg-primary/20 flex items-center justify-center shrink-0 mt-0.5">
                            <div className="h-1.5 w-1.5 rounded-full bg-primary" />
                          </div>
                          <div><p className="font-medium">{title}</p><p className="text-xs text-muted-foreground">{desc}</p></div>
                        </div>
                      ))}
                    </CardContent>
                  </Card>
                  <ResultPanel />
                </div>
              </div>
            </TabsContent>

            {/* ── Crop ── */}
            <TabsContent value="crop" className="mt-6">
              <div className="grid gap-6 lg:grid-cols-2">
                <div className="space-y-4">
                  <UploadZone />
                  <Card>
                    <CardHeader className="pb-2"><CardTitle className="text-base">Crop Mode</CardTitle></CardHeader>
                    <CardContent className="space-y-3">
                      <div className="grid grid-cols-2 gap-2">
                        {CROP_PRESETS.map(p => (
                          <button
                            key={p.value}
                            onClick={() => setCropMode(p.value)}
                            className={`h-14 rounded-lg border text-sm font-medium transition-colors flex flex-col items-center justify-center gap-0.5 ${cropMode === p.value ? "border-primary bg-primary/10 text-primary" : "border-border hover:border-primary/40"}`}
                          >
                            <span className="text-xl">{p.icon}</span>
                            <span className="text-xs">{p.label}</span>
                          </button>
                        ))}
                        <button
                          onClick={() => setCropMode("custom")}
                          className={`h-14 rounded-lg border text-sm font-medium transition-colors flex flex-col items-center justify-center gap-0.5 ${cropMode === "custom" ? "border-primary bg-primary/10 text-primary" : "border-border hover:border-primary/40"}`}
                        >
                          <span className="text-xl">📐</span>
                          <span className="text-xs">Custom</span>
                        </button>
                      </div>

                      {cropMode === "custom" && (
                        <div className="grid grid-cols-2 gap-3 pt-1">
                          <div><Label className="text-xs">Width (px)</Label>
                            <Input value={customW} onChange={e => setCustomW(e.target.value)} className="mt-1 h-9" /></div>
                          <div><Label className="text-xs">Height (px)</Label>
                            <Input value={customH} onChange={e => setCustomH(e.target.value)} className="mt-1 h-9" /></div>
                        </div>
                      )}

                      <Button className="w-full gradient-primary h-10 gap-2" onClick={applyCrop} disabled={!fileId || processing}>
                        {processing ? <RefreshCw className="h-4 w-4 animate-spin" /> : <Crop className="h-4 w-4" />} Apply Crop
                      </Button>
                    </CardContent>
                  </Card>
                </div>
                <div className="space-y-4">
                  {uploadedPreviewUrl && (
                    <div>
                      <p className="text-xs font-medium mb-2 text-muted-foreground">ORIGINAL</p>
                      <img src={uploadedPreviewUrl} alt="original" className="w-full rounded-xl border object-contain max-h-64 bg-muted/30" />
                    </div>
                  )}
                  <ResultPanel />
                </div>
              </div>
            </TabsContent>

            {/* ── Multi-Resize ── */}
            <TabsContent value="resize" className="mt-6">
              <div className="space-y-6">
                <div className="grid gap-6 lg:grid-cols-2">
                  <div className="space-y-4">
                    <UploadZone />
                    <Button className="w-full gradient-primary h-11 gap-2" onClick={handleAutoResize} disabled={!fileId || processing}>
                      {processing ? <RefreshCw className="h-4 w-4 animate-spin" /> : <Zap className="h-4 w-4" />}
                      Generate All Platform Sizes
                    </Button>
                  </div>
                  <Card>
                    <CardHeader className="pb-2"><CardTitle className="text-base">Supported Platforms</CardTitle></CardHeader>
                    <CardContent>
                      <div className="grid grid-cols-2 gap-2 text-sm">
                        {[["Instagram Square", "1080×1080"], ["Instagram Portrait", "1080×1350"], ["Amazon Listing", "2000×2000"], ["Thumbnail", "300×300"], ["Website Banner", "1920×1080"], ["Flipkart", "1600×2000"]].map(([name, size]) => (
                          <div key={name} className="flex justify-between items-center py-1.5 border-b border-border/50 last:border-0 col-span-2 gap-2">
                            <span className="font-medium">{name}</span>
                            <Badge variant="outline" className="text-xs font-mono">{size}</Badge>
                          </div>
                        ))}
                      </div>
                    </CardContent>
                  </Card>
                </div>

                {resizeResults.length > 0 && (
                  <div>
                    <h3 className="font-semibold mb-4">{resizeResults.length} Formats Generated</h3>
                    <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
                      {resizeResults.map((r, i) => (
                        <Card key={i} className="overflow-hidden">
                          <div className="aspect-square bg-muted/30 overflow-hidden">
                            <img src={r.url} alt={r.channel} className="w-full h-full object-contain" />
                          </div>
                          <CardContent className="p-3">
                            <p className="font-medium capitalize text-sm">{r.channel.replace(/_/g, " ")}</p>
                            <p className="text-xs text-muted-foreground">{r.width}×{r.height}px</p>
                            <Button size="sm" className="w-full mt-2 h-8 gap-1.5 gradient-primary text-xs" onClick={() => downloadResult(r.url, `${r.channel}.png`)}>
                              <Download className="h-3 w-3" /> Download
                            </Button>
                          </CardContent>
                        </Card>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            </TabsContent>
          </Tabs>
        </div>
      </div>
    </div>
  )
}
